package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python list object.
 */
public class PyListObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    public PyListObj(List<E> value) {
        super(value);
    }

    @Override
    public String toString() {
        return "[" + getValue().stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + "]";
    }
}

package main.rice.obj;

import java.util.Objects;

/**
 * Abstract base class for all Python objects.
 */
public abstract class APyObj<T> {

    private final T value;

    protected APyObj(T value) {
        this.value = value;
    }

    public T getValue() {
        return value;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || this.getClass() != obj.getClass()) return false;
        APyObj<?> other = (APyObj<?>) obj;
        return Objects.equals(this.value, other.value);
    }

    @Override
    public int hashCode() {
        return Objects.hash(this.getClass(), value);
    }

    @Override
    public abstract String toString();
}

