package main.rice.obj;

/**
 * Abstract base class for all iterable Python objects.
 */
public abstract class AIterablePyObj<T> extends APyObj<T> {

    protected AIterablePyObj(T value) {
        super(value);
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * Represents a Python string object. Internally stores characters as a List<PyCharObj>.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {

    public PyStringObj(String value) {
        super(toCharList(value));
    }

    private static List<PyCharObj> toCharList(String s) {
        List<PyCharObj> chars = new ArrayList<>();
        for (char c : s.toCharArray()) {
            chars.add(new PyCharObj(c));
        }
        return chars;
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("'");
        for (PyCharObj c : getValue()) {
            sb.append(c.getValue());
        }
        sb.append("'");
        return sb.toString();
    }
}

