package main.rice.obj;

import java.util.Set;
import java.util.stream.Collectors;

/**
 * Represents a Python set object.
 */
public class PySetObj<E extends APyObj<?>> extends AIterablePyObj<Set<E>> {

    public PySetObj(Set<E> value) {
        super(value);
    }

    @Override
    public String toString() {
        Set<E> elems = getValue();
        if (elems.isEmpty()) {
            return "set()";
        }
        return "{" + elems.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + "}";
    }
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True or False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        super(value);
    }

    @Override
    public String toString() {
        return getValue() ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python tuple object.
 */
public class PyTupleObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    public PyTupleObj(List<E> value) {
        super(value);
    }

    @Override
    public String toString() {
        List<E> elems = getValue();
        if (elems.size() == 1) {
            return "(" + elems.get(0).toString() + ",)";
        }
        return "(" + elems.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + ")";
    }
}

package main.rice.obj;

/**
 * Represents a Python character object.
 */
public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        super(value);
    }

    @Override
    public String toString() {
        return getValue().toString();
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.stream.Collectors;

/**
 * Represents a Python dictionary object.
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        super(value);
    }

    @Override
    public String toString() {
        Map<K, V> map = getValue();
        if (map.isEmpty()) {
            return "{}";
        }
        return "{" + map.entrySet().stream()
            .map(e -> e.getKey().toString() + ": " + e.getValue().toString())
            .collect(Collectors.joining(", ")) + "}";
    }
}

